import { describe, expect, it } from 'vitest';
import {
  solarSlope,
  classifyPhaseDirection,
  phaseScore,
  scheduleScore,
  scoreNodes,
  routeToSunrise,
  routeToSunriseK,
  sampleTerminator,
  simulateWorkFlow,
  summarizeWorkFlow,
} from './solar-scheduler';
import type { SolarSchedulerNode } from './solar-scheduler';

// Test fixture: June 21 solstice, 12:00 UTC (summer in northern hemisphere)
const NOW_MS = Date.UTC(2026, 5, 21, 12, 0, 0);
const ONE_HOUR_MS = 3_600_000;

// Network: PIDs at key datacenters around the globe
const sfPid: SolarSchedulerNode = {
  pidId: 'pid:sf', label: 'SF', lat: 37.77, lon: -122.42,
  capacity: 1000, currentLoad: 200, phase: 'active',
};
const tokyoPid: SolarSchedulerNode = {
  pidId: 'pid:tokyo', label: 'Tokyo', lat: 35.68, lon: 139.69,
  capacity: 1000, currentLoad: 800, phase: 'active',
};
const londonPid: SolarSchedulerNode = {
  pidId: 'pid:london', label: 'London', lat: 51.51, lon: -0.13,
  capacity: 1000, currentLoad: 500, phase: 'active',
};
const sydneyPid: SolarSchedulerNode = {
  pidId: 'pid:sydney', label: 'Sydney', lat: -33.87, lon: 151.21,
  capacity: 1000, currentLoad: 100, phase: 'idle',
};

const allNodes = [sfPid, tokyoPid, londonPid, sydneyPid];

// ─── Slope Computation ──────────────────────────────────────────────

describe('solarSlope', () => {
  it('is positive at dawn (east coast, early morning)', () => {
    // New York around sunrise in June
    const nyc = { latitudeDeg: 40.7, longitudeDeg: -74 };
    const dawn = Date.UTC(2026, 5, 21, 9, 0, 0); // 5am EDT
    const slope = solarSlope(nyc, dawn);
    expect(slope).toBeGreaterThan(0);
  });

  it('is negative at dusk (east coast, late evening)', () => {
    const nyc = { latitudeDeg: 40.7, longitudeDeg: -74 };
    const dusk = Date.UTC(2026, 5, 21, 23, 30, 0); // 7:30pm EDT
    const slope = solarSlope(nyc, dusk);
    expect(slope).toBeLessThan(0);
  });

  it('is near zero at solar noon', () => {
    const equator = { latitudeDeg: 0, longitudeDeg: 0 };
    const noon = Date.UTC(2026, 5, 21, 12, 0, 0); // noon at prime meridian
    const slope = solarSlope(equator, noon);
    expect(Math.abs(slope)).toBeLessThan(2); // slope very small near peak
  });
});

// ─── Phase Classification ───────────────────────────────────────────

describe('classifyPhaseDirection', () => {
  it('classifies rising phase: low altitude + positive slope', () => {
    expect(classifyPhaseDirection(10, 8)).toBe('rising');
  });

  it('classifies peak phase: high altitude + small slope', () => {
    expect(classifyPhaseDirection(60, 1)).toBe('peak');
  });

  it('classifies falling phase: low altitude + negative slope', () => {
    expect(classifyPhaseDirection(10, -8)).toBe('falling');
  });

  it('classifies night phase: negative altitude', () => {
    expect(classifyPhaseDirection(-30, 0)).toBe('night');
  });

  it('night threshold is -5 degrees', () => {
    expect(classifyPhaseDirection(-6, 0)).toBe('night');
    expect(classifyPhaseDirection(-4, 5)).toBe('rising');
  });
});

// ─── Phase Score ────────────────────────────────────────────────────

describe('phaseScore', () => {
  it('ranks rising highest', () => {
    expect(phaseScore('rising')).toBe(0.9);
  });

  it('ranks night second (spare capacity)', () => {
    expect(phaseScore('night')).toBe(0.8);
  });

  it('penalizes falling heavily', () => {
    expect(phaseScore('falling')).toBe(0.2);
  });

  it('rising beats peak (more headroom)', () => {
    expect(phaseScore('rising')).toBeGreaterThan(phaseScore('peak'));
  });

  it('night beats falling (spare capacity > wasted warmth)', () => {
    expect(phaseScore('night')).toBeGreaterThan(phaseScore('falling'));
  });
});

// ─── Schedule Score ─────────────────────────────────────────────────

describe('scheduleScore', () => {
  it('returns capacity and utilization metrics', () => {
    const s = scheduleScore(sfPid, NOW_MS);
    expect(s.capacityAvailable).toBe(800); // 1000 - 200
    expect(s.utilizationFraction).toBeCloseTo(0.2);
  });

  it('saturated node scores lower than idle node', () => {
    const nearLoad = { ...sfPid, currentLoad: 950 };
    const nearIdle = { ...sfPid, pidId: 'pid:sf2', currentLoad: 50 };
    const s1 = scheduleScore(nearLoad, NOW_MS);
    const s2 = scheduleScore(nearIdle, NOW_MS);
    expect(s2.score).toBeGreaterThan(s1.score);
  });

  it('unreachable node scores zero', () => {
    const dead = { ...sfPid, phase: 'unreachable' as const };
    const s = scheduleScore(dead, NOW_MS);
    expect(s.score).toBe(0);
  });

  it('cold node scores nearly zero', () => {
    const cold = { ...sfPid, phase: 'cold' as const };
    const active = { ...sfPid, pidId: 'pid:sf2', phase: 'active' as const };
    const sCold = scheduleScore(cold, NOW_MS);
    const sActive = scheduleScore(active, NOW_MS);
    expect(sCold.score).toBeLessThan(sActive.score);
  });
});

// ─── Scoring & Routing ──────────────────────────────────────────────

describe('scoreNodes', () => {
  it('returns nodes sorted by descending score', () => {
    const scored = scoreNodes(allNodes, NOW_MS);
    for (let i = 1; i < scored.length; i++) {
      expect(scored[i - 1].score).toBeGreaterThanOrEqual(scored[i].score);
    }
  });

  it('returns one score per node', () => {
    const scored = scoreNodes(allNodes, NOW_MS);
    expect(scored.length).toBe(allNodes.length);
  });
});

describe('routeToSunrise', () => {
  it('picks a node with positive score when available', () => {
    const best = routeToSunrise(allNodes, NOW_MS);
    expect(best).not.toBeNull();
    expect(best!.score).toBeGreaterThan(0);
  });

  it('returns null if all nodes are saturated', () => {
    const saturated = allNodes.map(n => ({ ...n, currentLoad: n.capacity }));
    const best = routeToSunrise(saturated, NOW_MS);
    expect(best).toBeNull();
  });

  it('returns null when all nodes unreachable', () => {
    const dead = allNodes.map(n => ({ ...n, phase: 'unreachable' as const }));
    const best = routeToSunrise(dead, NOW_MS);
    expect(best).toBeNull();
  });

  it('different times select different nodes as terminator moves', () => {
    // Midnight UTC -- Pacific daytime
    const pidsAtMidnight = routeToSunrise(allNodes, Date.UTC(2026, 5, 21, 0, 0, 0));
    // Noon UTC -- European/African daytime
    const pidsAtNoon = routeToSunrise(allNodes, Date.UTC(2026, 5, 21, 12, 0, 0));
    expect(pidsAtMidnight).not.toBeNull();
    expect(pidsAtNoon).not.toBeNull();
    // Over a full 12-hour span, the dominant node should have shifted
    // (not guaranteed for every pair of times but true across wide windows)
  });
});

describe('routeToSunriseK', () => {
  it('returns at most k nodes', () => {
    const top2 = routeToSunriseK(allNodes, 2, NOW_MS);
    expect(top2.length).toBeLessThanOrEqual(2);
  });

  it('returns empty array for k=0', () => {
    expect(routeToSunriseK(allNodes, 0, NOW_MS).length).toBe(0);
  });

  it('results are sorted by descending score', () => {
    const top3 = routeToSunriseK(allNodes, 3, NOW_MS);
    for (let i = 1; i < top3.length; i++) {
      expect(top3[i - 1].score).toBeGreaterThanOrEqual(top3[i].score);
    }
  });
});

// ─── Terminator Geometry ────────────────────────────────────────────

describe('sampleTerminator', () => {
  const points = sampleTerminator(NOW_MS, 10);

  it('produces both sunrise and sunset points', () => {
    const sunrises = points.filter(p => p.side === 'sunrise');
    const sunsets = points.filter(p => p.side === 'sunset');
    expect(sunrises.length).toBeGreaterThan(0);
    expect(sunsets.length).toBeGreaterThan(0);
  });

  it('longitudes are in [-180, 180]', () => {
    for (const p of points) {
      expect(p.lon).toBeGreaterThanOrEqual(-180);
      expect(p.lon).toBeLessThanOrEqual(180);
    }
  });

  it('at the summer solstice, the terminator avoids extreme polar latitudes', () => {
    // At northern solstice, arctic circle has 24h daylight -- no terminator
    // at 80°N or 80°S near the lit polar cap
    const atHighLat = points.filter(p => Math.abs(p.lat) > 70);
    // Some should exist (terminator still wraps around) but far fewer than temperate
    const atMidLat = points.filter(p => Math.abs(p.lat) < 50);
    expect(atMidLat.length).toBeGreaterThan(atHighLat.length);
  });
});

// ─── Work Flow Simulation ───────────────────────────────────────────

describe('simulateWorkFlow', () => {
  it('produces a step per hour over the window', () => {
    const start = NOW_MS;
    const end = start + 24 * ONE_HOUR_MS;
    const steps = simulateWorkFlow(allNodes, start, end, ONE_HOUR_MS);
    expect(steps.length).toBe(25); // 24 hours + endpoint
  });

  it('work distributes across multiple nodes over 24 hours', () => {
    const start = Date.UTC(2026, 5, 21, 0, 0, 0);
    const end = start + 24 * ONE_HOUR_MS;
    const steps = simulateWorkFlow(allNodes, start, end, ONE_HOUR_MS);
    const uniqueTargets = new Set(steps.map(s => s.targetPidId));
    // Over a full day, work should rotate through at least 2 nodes
    expect(uniqueTargets.size).toBeGreaterThanOrEqual(2);
  });
});

describe('summarizeWorkFlow', () => {
  it('counts steps per node and computes fractions', () => {
    const start = Date.UTC(2026, 5, 21, 0, 0, 0);
    const end = start + 24 * ONE_HOUR_MS;
    const steps = simulateWorkFlow(allNodes, start, end, ONE_HOUR_MS);
    const summary = summarizeWorkFlow(steps);

    expect(summary.source).toBe('GnosisSolarSchedulerDistribution');
    expect(summary.totalSteps).toBe(steps.length);

    // Fractions sum to 1
    let sum = 0;
    for (const frac of summary.perNodeFraction.values()) {
      sum += frac;
    }
    expect(sum).toBeCloseTo(1, 3);
  });

  it('identifies the dominant node', () => {
    const steps = [
      { epochMs: 0, targetPidId: 'a', targetLabel: 'A', score: 0.5, phaseDirection: 'rising' as const },
      { epochMs: 1, targetPidId: 'a', targetLabel: 'A', score: 0.5, phaseDirection: 'rising' as const },
      { epochMs: 2, targetPidId: 'b', targetLabel: 'B', score: 0.3, phaseDirection: 'night' as const },
    ];
    const summary = summarizeWorkFlow(steps);
    expect(summary.dominantPidId).toBe('a');
  });

  it('returns null dominant for empty steps', () => {
    const summary = summarizeWorkFlow([]);
    expect(summary.dominantPidId).toBeNull();
  });
});
